sys_script.script:
// Before delete BR on x_snc_airop_check_definition
// Blocks delete if check results exist, otherwise cleans up AROPCheckLibrary

var defSysId  = current.getUniqueValue();
var num       = current.getValue('number');
var handler   = current.getValue('check_handler');
var checkName = current.getValue('check_name');

// Step 1: Check for existing results referencing this definition
var results = new GlideRecord('x_snc_airop_check_result');
results.addQuery('check_definition', defSysId);
results.setLimit(1);
results.query();

if (results.next()) {
    // Block the delete
    current.setAbortAction(true);
    gs.addErrorMessage(
        'Cannot delete "' + checkName + '" -- historical check results exist for this definition. ' +
        'Deactivate it instead to prevent it from running in future assessments.'
    );
    gs.info('[AIROP] Delete blocked on ' + num + ' -- check results exist.');
} else {
    // Safe to delete -- remove method from AROPCheckLibrary first
    if (handler) {
        var si = new GlideRecord('sys_script_include');
        si.addQuery('name', 'AROPCheckLibrary');
        si.setLimit(1);
        si.query();

        if (si.next()) {
            var libScript = si.getValue('script');
            var searchStr = '    ' + handler + ': function()';

            if (libScript.indexOf(searchStr) > -1) {
                var removed = 0;
                while (libScript.indexOf(searchStr) > -1) {
                    var mStart = libScript.indexOf(searchStr);
                    var depth=0; var mEnd=mStart; var inM=false;
                    for (var c=mStart; c<libScript.length; c++) {
                        if (libScript[c]==='{') { depth++; inM=true; }
                        if (libScript[c]==='}') depth--;
                        if (inM&&depth===0) { mEnd=c+1; if(libScript[mEnd]===',') mEnd++; if(libScript[mEnd]==='\n') mEnd++; break; }
                    }
                    libScript = libScript.substring(0,mStart) + libScript.substring(mEnd);
                    removed++;
                }
                si.setValue('script', libScript);
                si.setWorkflow(false);
                si.update();
                gs.info('[AIROP] Removed ' + removed + ' method copies from AROPCheckLibrary: ' + handler);
            } else {
                gs.info('[AIROP] Method not in library -- nothing to clean up.');
            }
        }
    }
    gs.info('[AIROP] Safe delete proceeding for: ' + num + ' - ' + checkName);
}
